package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.nio.charset.StandardCharsets;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserTest {

    @Test
    void testParse_withValidInputStreamAndCharsetAndFormat() throws IOException {
        // Arrange
        String csvContent = "header1,header2\nvalue1,value2\n";
        InputStream inputStream = new ByteArrayInputStream(csvContent.getBytes(StandardCharsets.UTF_8));
        Charset charset = StandardCharsets.UTF_8;
        CSVFormat format = mock(CSVFormat.class);

        // Mock Assertions.notNull to do nothing (assuming it's a static method)
        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(inputStream, "inputStream")).thenReturn(null);
            mockedAssertions.when(() -> Assertions.notNull(format, "format")).thenReturn(null);

            // Mock CSVParser.parse(Reader, CSVFormat) to return a dummy CSVParser
            try (MockedStatic<CSVParser> mockedCSVParser = Mockito.mockStatic(CSVParser.class)) {
                CSVParser dummyParser = mock(CSVParser.class);
                mockedCSVParser.when(() -> CSVParser.parse(any(java.io.Reader.class), eq(format)))
                        .thenReturn(dummyParser);

                // Act
                CSVParser result = CSVParser.parse(inputStream, charset, format);

                // Assert
                assertNotNull(result);
                assertEquals(dummyParser, result);

                // Verify that the static methods were called correctly
                mockedAssertions.verify(() -> Assertions.notNull(inputStream, "inputStream"));
                mockedAssertions.verify(() -> Assertions.notNull(format, "format"));
                mockedCSVParser.verify(() -> CSVParser.parse(any(java.io.Reader.class), eq(format)));
            }
        }
    }

    @Test
    void testParse_withNullInputStream_throwsException() {
        InputStream inputStream = null;
        Charset charset = StandardCharsets.UTF_8;
        CSVFormat format = mock(CSVFormat.class);

        // We expect Assertions.notNull to throw a NullPointerException or IllegalArgumentException
        // Since we don't have Assertions code, simulate it by mocking static method to throw
        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(inputStream, "inputStream"))
                    .thenThrow(new NullPointerException("inputStream"));

            assertThrows(NullPointerException.class, () -> CSVParser.parse(inputStream, charset, format));

            mockedAssertions.verify(() -> Assertions.notNull(inputStream, "inputStream"));
            // format check should not be called because inputStream check fails first
            mockedAssertions.verifyNoMoreInteractions();
        }
    }

    @Test
    void testParse_withNullFormat_throwsException() {
        String csvContent = "header1,header2\nvalue1,value2\n";
        InputStream inputStream = new ByteArrayInputStream(csvContent.getBytes(StandardCharsets.UTF_8));
        Charset charset = StandardCharsets.UTF_8;
        CSVFormat format = null;

        try (MockedStatic<Assertions> mockedAssertions = Mockito.mockStatic(Assertions.class)) {
            mockedAssertions.when(() -> Assertions.notNull(inputStream, "inputStream")).thenReturn(null);
            mockedAssertions.when(() -> Assertions.notNull(format, "format"))
                    .thenThrow(new NullPointerException("format"));

            assertThrows(NullPointerException.class, () -> CSVParser.parse(inputStream, charset, format));

            mockedAssertions.verify(() -> Assertions.notNull(inputStream, "inputStream"));
            mockedAssertions.verify(() -> Assertions.notNull(format, "format"));
            mockedAssertions.verifyNoMoreInteractions();
        }
    }
}
